<?php
 namespace WPAICG\AutoGPT\Cron\Init; if (!defined('ABSPATH')) { exit; } function register_main_cron_hook_logic(string $main_cron_hook, int $active_task_count, int $pending_queue_count, bool $did_active_tasks_exist): void { $option_key_tasks_exist = 'aipkit_active_tasks_exist'; $has_work_to_do = ($active_task_count > 0) || ($pending_queue_count > 0); if (!$has_work_to_do) { if ($did_active_tasks_exist && wp_next_scheduled($main_cron_hook)) { wp_clear_scheduled_hook($main_cron_hook); } update_option($option_key_tasks_exist, false, 'no'); } else { if (!$did_active_tasks_exist) { update_option($option_key_tasks_exist, true, 'no'); } if (!wp_next_scheduled($main_cron_hook)) { wp_schedule_event(time(), 'hourly', $main_cron_hook); } } } 